module RefModule (
    input wire A,
    input wire B,
    input wire C,
    output wire Y
);
    wire unused_AB, BC, AC; // Intermediate signals for the product terms

    assign unused_AB = A & B; // Product term for A and B
    assign BC = B & C; // Product term for B and C
    assign AC = A & C; // Product term for A and C

    // Resolve hazards by ensuring stable outputs
    assign Y = (unused_AB | BC | AC);

endmodule
